"use client";

import React from 'react';
import Link from 'next/link';
import { motion, useMotionTemplate, useMotionValue } from 'framer-motion';
import { 
  Globe, 
  Smartphone, 
  TrendingUp, 
  FolderKanban, 
  Leaf, 
  Brain, 
  ShieldCheck, 
  TreePine,
  ArrowUpRight,
  LucideIcon 
} from 'lucide-react';

// --- Types ---
interface Service {
  icon: LucideIcon;
  title: string;
  description: string;
  href: string;
}

interface ServiceCardProps extends Service {
  index: number;
}

// --- Data ---
const services: Service[] = [
  {
    icon: Globe,
    title: 'Web Application',
    description: 'Custom web solutions built with modern technologies for scalability and performance.',
    href: '/services/web-application',
  },
  {
    icon: Smartphone,
    title: 'Mobile Application',
    description: 'Native and cross-platform mobile apps that deliver exceptional user experiences.',
    href: '/services/mobile-application',
  },
  {
    icon: TrendingUp,
    title: 'Digital Marketing',
    description: 'Data-driven marketing strategies that amplify your brand and drive conversions.',
    href: '/services/digital-marketing',
  },
  {
    icon: FolderKanban,
    title: 'Project Management',
    description: 'Expert project oversight ensuring on-time, on-budget delivery every time.',
    href: '/services/project-management',
  },
  {
    icon: Leaf,
    title: 'Agri-Business',
    description: 'Innovative agricultural solutions leveraging technology for sustainable farming.',
    href: '/services/agri-business',
  },
  {
    icon: Brain,
    title: 'Data Science/AI',
    description: 'Advanced analytics and AI solutions that transform raw data into actionable insights.',
    href: '/services/data-science-ai',
  },
  {
    icon: ShieldCheck,
    title: 'Quality Assurance',
    description: 'Comprehensive testing services ensuring software reliability and excellence.',
    href: '/services/quality-assurance',
  },
  {
    icon: TreePine,
    title: 'Environmental Services',
    description: 'Sustainable solutions for environmental monitoring and compliance.',
    href: '/services/environmental-services',
  },
];

// --- Sub-component: ServiceCard ---
const ServiceCard = ({ icon: Icon, title, description, href, index }: ServiceCardProps) => {
  const mouseX = useMotionValue(0);
  const mouseY = useMotionValue(0);

  function handleMouseMove({ currentTarget, clientX, clientY }: React.MouseEvent) {
    const { left, top } = currentTarget.getBoundingClientRect();
    mouseX.set(clientX - left);
    mouseY.set(clientY - top);
  }

  return (
    <motion.div
      initial={{ opacity: 0, y: 30 }}
      whileInView={{ opacity: 1, y: 0 }}
      viewport={{ once: true }}
      transition={{ delay: index * 0.1, duration: 0.5 }}
      onMouseMove={handleMouseMove}
      className="group relative h-full"
    >
      <Link
        href={href}
        className="block relative h-full p-8 rounded-[2.5rem] bg-white border border-slate-100/50 shadow-[0_20px_50px_-12px_rgba(0,0,0,0.08)] transition-all duration-500 hover:shadow-[0_40px_80px_-15px_rgba(0,51,102,0.15)] hover:-translate-y-4 overflow-hidden flex flex-col"
      >
        {/* Top Branding Accent Bar */}
        <div className="absolute top-0 left-0 w-full h-1.5 bg-gradient-to-r from-[#003366] via-blue-500 to-cyan-400 opacity-30 group-hover:opacity-100 transition-opacity duration-500" />

        {/* Hover Spotlight Glow */}
        <motion.div
          className="pointer-events-none absolute -inset-px rounded-[2.5rem] opacity-0 group-hover:opacity-100 transition duration-300"
          style={{
            background: useMotionTemplate`
              radial-gradient(
                450px circle at ${mouseX}px ${mouseY}px,
                rgba(0, 51, 102, 0.05),
                transparent 80%
              )
            `,
          }}
        />

        <div className="relative z-10 flex flex-col h-full">
          {/* Prominent Icon Box */}
          <div className="w-16 h-16 rounded-2xl bg-slate-50 border border-slate-100 flex items-center justify-center mb-8 group-hover:scale-110 group-hover:bg-[#003366] group-hover:shadow-lg group-hover:shadow-blue-500/20 transition-all duration-500 shadow-inner">
            <Icon className="w-8 h-8 text-[#003366] group-hover:text-white transition-colors duration-500" />
          </div>

          {/* Title */}
          <h3 className="text-2xl font-bold text-slate-900 mb-4 tracking-tight group-hover:text-[#003366] transition-colors">
            {title}
          </h3>

          {/* Description */}
          <p className="text-slate-500 text-sm leading-relaxed mb-8 line-clamp-3">
            {description}
          </p>

          {/* Detailed CTA */}
          <div className="mt-auto flex items-center justify-between pt-4 border-t border-slate-50">
            <span className="text-[10px] font-bold uppercase tracking-[0.2em] text-slate-400 group-hover:text-[#003366] transition-colors">
              Service Details
            </span>
            <div className="w-8 h-8 rounded-full bg-slate-100 flex items-center justify-center group-hover:bg-cyan-400 group-hover:text-white transition-all duration-300">
              <ArrowUpRight className="w-4 h-4" />
            </div>
          </div>
        </div>
      </Link>
    </motion.div>
  );
};

// --- Main Component: ServicesSection ---
export const ServicesSection = () => {
  return (
    <section className="py-24 relative overflow-hidden bg-white">
      <div className="container mx-auto px-4 relative z-10">
        <motion.div
          initial={{ opacity: 0, y: 30 }}
          whileInView={{ opacity: 1, y: 0 }}
          viewport={{ once: true }}
          transition={{ duration: 0.8 }}
          className="text-center mb-20"
        >
          {/* High-Impact Gradient Heading */}
          <h2 className="text-4xl md:text-6xl font-black text-slate-900 tracking-tight mb-6 leading-[1.1]">
            Comprehensive <br className="hidden md:block" />
            <span className="text-transparent bg-clip-text bg-gradient-to-r from-[#003366] via-[#004d99] to-cyan-500">
              Solutions
            </span> for Your Business
          </h2>

          {/* Refined Subtext */}
          <p className="text-slate-500 max-w-2xl mx-auto text-lg md:text-xl leading-relaxed">
            From web development to AI-powered analytics, we offer a full spectrum of 
            services designed to accelerate your digital transformation.
          </p>

          {/* Modern Accent Line */}
          <motion.div 
            initial={{ width: 0, opacity: 0 }}
            whileInView={{ width: "80px", opacity: 1 }}
            transition={{ delay: 0.5, duration: 1 }}
            className="h-1.5 bg-gradient-to-r from-[#003366] to-cyan-400 mx-auto mt-10 rounded-full"
          />
        </motion.div>

        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-8">
          {services.map((service, index) => (
            <ServiceCard
              key={service.href}
              index={index}
              {...service}
            />
          ))}
        </div>
      </div>
    </section>
  );
};