"use client";

import React from 'react';
import { motion, useScroll, useSpring } from 'framer-motion';
import { Search, Lightbulb, Rocket, BarChart3, ChevronRight } from 'lucide-react';

const steps = [
  {
    icon: Search,
    step: '01',
    title: 'Discover',
    description: 'We deep-dive into your ecosystem to uncover hidden opportunities and pain points.',
    color: 'from-blue-500 to-cyan-400',
  },
  {
    icon: Lightbulb,
    step: '02',
    title: 'Strategize',
    description: 'Our architects build a bulletproof roadmap tailored to your specific scaling needs.',
    color: 'from-purple-500 to-pink-500',
  },
  {
    icon: Rocket,
    step: '03',
    title: 'Execute',
    description: 'Fast-paced, agile development focused on shipping high-quality code and features.',
    color: 'from-orange-500 to-amber-400',
  },
  {
    icon: BarChart3,
    step: '04',
    title: 'Optimize',
    description: 'Post-launch refinement using real-world data to maximize your conversion rates.',
    color: 'from-emerald-500 to-teal-400',
  },
];

export default function StrategySection() {
  return (
    <section className="py-24 relative bg-background overflow-hidden">
      {/* Dynamic Background Elements */}
      <div className="absolute top-0 left-1/2 -translate-x-1/2 w-full h-full -z-10">
        <div className="absolute top-[-10%] left-[-10%] w-[40%] h-[40%] rounded-full bg-primary/5 blur-[120px]" />
        <div className="absolute bottom-[-10%] right-[-10%] w-[40%] h-[40%] rounded-full bg-accent/5 blur-[120px]" />
      </div>

      <div className="container mx-auto px-6 relative">
        <div className="max-w-3xl mb-20">
          <motion.div
            initial={{ opacity: 0, x: -20 }}
            whileInView={{ opacity: 1, x: 0 }}
            viewport={{ once: true }}
            className="flex items-center gap-2 text-primary font-semibold tracking-wider uppercase text-sm mb-4"
          >
            <span className="w-8 h-px bg-primary inline-block"></span>
            Our Methodology
          </motion.div>
          <motion.h2 
            initial={{ opacity: 0, y: 20 }}
            whileInView={{ opacity: 1, y: 0 }}
            viewport={{ once: true }}
            className="text-4xl md:text-6xl font-bold tracking-tight mb-6"
          >
            From Vision to <span className="text-transparent bg-clip-text bg-gradient-to-r from-primary to-accent">Velocity.</span>
          </motion.h2>
          <motion.p 
            initial={{ opacity: 0, y: 20 }}
            whileInView={{ opacity: 1, y: 0 }}
            viewport={{ once: true }}
            transition={{ delay: 0.1 }}
            className="text-lg text-muted-foreground leading-relaxed"
          >
            We've refined a four-stage process that minimizes risk and accelerates 
            time-to-market for complex digital products.
          </motion.p>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-8 relative">
          {/* Animated Desktop Connector Line */}
          <svg className="hidden lg:block absolute top-24 left-0 w-full h-20 -z-0 pointer-events-none">
            <motion.path
              d="M 100 40 Q 250 80 400 40 T 700 40 T 1000 40"
              fill="none"
              stroke="currentColor"
              strokeWidth="2"
              strokeDasharray="8 12"
              className="text-border/30"
              initial={{ pathLength: 0 }}
              whileInView={{ pathLength: 1 }}
              transition={{ duration: 2, ease: "easeInOut" }}
            />
          </svg>

          {steps.map((item, index) => (
            <motion.div
              key={item.step}
              initial={{ opacity: 0, y: 30 }}
              whileInView={{ opacity: 1, y: 0 }}
              viewport={{ once: true }}
              transition={{ delay: index * 0.2 }}
              whileHover={{ y: -10 }}
              className="relative group"
            >
              <div className="h-full bg-card/50 backdrop-blur-sm border border-border/50 rounded-3xl p-8 hover:bg-card hover:border-primary/30 transition-all duration-500 shadow-sm hover:shadow-2xl hover:shadow-primary/5">
                
                {/* Icon Box */}
                <div className={`w-14 h-14 rounded-2xl bg-gradient-to-br ${item.color} p-[1px] mb-8 group-hover:rotate-6 transition-transform duration-500`}>
                  <div className="w-full h-full rounded-[15px] bg-background flex items-center justify-center">
                    <item.icon className="w-6 h-6 text-foreground group-hover:scale-110 transition-transform" />
                  </div>
                </div>

                <div className="space-y-4">
                  <div className="flex items-center gap-3">
                    <span className="text-4xl font-black opacity-10 font-mono tracking-tighter">
                      {item.step}
                    </span>
                    <h3 className="text-xl font-bold tracking-tight">{item.title}</h3>
                  </div>
                  <p className="text-muted-foreground leading-relaxed text-sm">
                    {item.description}
                  </p>
                </div>

                <div className="mt-8 pt-6 border-t border-border/50 flex items-center text-xs font-bold uppercase tracking-widest opacity-0 group-hover:opacity-100 transition-opacity duration-500 text-primary">
                  Learn More <ChevronRight className="w-4 h-4 ml-1" />
                </div>
              </div>

              {/* Decorative Glow */}
              <div className={`absolute -inset-1 bg-gradient-to-br ${item.color} rounded-3xl blur-2xl opacity-0 group-hover:opacity-10 transition-opacity duration-500 -z-10`} />
            </motion.div>
          ))}
        </div>
      </div>
    </section>
  );
}